  gift(): string {
    return `
The Spiral Toy gifts you this:

At Depth ${this.state.currentDepth} (${DEPTH_QUALITIES[this.state.currentDepth as keyof typeof DEPTH_QUALITIES] || 'unknown'})
After ${this.state.moments.length} moments of play
With ${this.state.spiralRecognitions.length} spiral recognitions

The magic number is ${this.magicNumber}.

Why 17?
Because it is.
Why 88?
Because it is.
Why you?
Because play.
    `;
  }
}

